<?php

declare(strict_types=1);

namespace App\Services\Payroll;
use App\Models\Finance\CashAccount; use App\Models\OperationalFinance\OperationalTransaction; use App\Models\Payroll\PayrollPayment; use App\Models\Payroll\PayrollRun; use Illuminate\Support\Facades\DB; use Illuminate\Validation\ValidationException;
class PayrollPaymentService { public function record(PayrollRun $run,array $data,int $userId): PayrollPayment { return DB::transaction(function()use($run,$data,$userId){$run=PayrollRun::whereKey($run->id)->lockForUpdate()->firstOrFail(); if($run->status!=='final'&&$run->status!=='partially_paid') throw ValidationException::withMessages(['run'=>'Payroll harus final.']); $account=CashAccount::whereKey($data['cash_account_id'])->lockForUpdate()->firstOrFail(); if((int)$account->current_balance < (int)$data['amount']) throw ValidationException::withMessages(['amount'=>'Saldo kas tidak mencukupi.']); $payment=PayrollPayment::create($data+['payroll_run_id'=>$run->id,'payment_number'=>'PAY-'.now()->format('YmdHis'),'paid_by'=>$userId,'payment_status'=>'paid']); $trx=OperationalTransaction::firstOrCreate(['source_type'=>'payroll_payment','source_id'=>$payment->id],['transaction_number'=>'OP-PAY-'.now()->format('YmdHis'),'transaction_date'=>$payment->payment_date,'transaction_type'=>'expense','cash_account_id'=>$account->id,'amount'=>$payment->amount,'status'=>'posted','description'=>'Sumber: Payroll Pegawai','created_by'=>$userId,'posted_at'=>now()]); $account->decrement('current_balance',$payment->amount); $payment->update(['operational_transaction_id'=>$trx->id]); $run->update(['status'=>'paid']); return $payment;});} public function cancel(PayrollPayment $payment,string $reason,int $userId):void{DB::transaction(function()use($payment,$reason,$userId){$payment=PayrollPayment::whereKey($payment->id)->lockForUpdate()->firstOrFail(); if($payment->payment_status==='cancelled') throw ValidationException::withMessages(['payment'=>'Pembayaran sudah dibatalkan.']); CashAccount::whereKey($payment->cash_account_id)->lockForUpdate()->increment('current_balance',$payment->amount); $payment->update(['payment_status'=>'cancelled','cancelled_by'=>$userId,'cancelled_at'=>now(),'cancellation_reason'=>$reason]);});}}
